SELECT t.id, t.user_id AS userId, COALESCE(u.nickname, u.login_name) AS userName, t.model_name AS modelName, t.scene, t.input_tokens AS inputTokens, t.output_tokens AS outputTokens, t.total_tokens AS totalTokens, t.created_at AS createdAt FROM ai_token_usage t LEFT JOIN `user` u ON t.user_id = u.id
t.created_at BETWEEN #{start} AND #{end}
AND t.model_name = #{model}
AND t.scene = #{scene}
ORDER BY t.id DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM ai_token_usage t

    t.created_at BETWEEN #{start} AND #{end}

        AND t.model_name = #{model}


        AND t.scene = #{scene}
